/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ETG_ChargeCodes, Estimation), FormControlEventType::Clicked)]
public static void Estimation_OnClicked(FormControl sender, FormControlEventArgs e)
{
    FormDataSource          ETGChargeCodes_DS = sender.formRun().dataSource(formDataSourceStr(ETG_ChargeCodes, ETGChargeCodes));
    MultiSelectionHelper    selectionHelper = MultiSelectionHelper::construct();
    ETG_ChargeCodes         eTGChargeCodes;
    ETGCreateJournalHelper  eTGCreateJournalHelper = new ETGCreateJournalHelper();

    selectionHelper.parmDataSource(ETGChargeCodes_DS);
    eTGChargeCodes  = selectionHelper.getFirst();

    if (eTGChargeCodes.RecId)
    {
        while (eTGChargeCodes.RecId != 0)
        {
            eTGCreateJournalHelper.CreateJnlEntry(eTGChargeCodes.ETG_Estimation);
            eTGChargeCodes = selectionHelper.getNext();
        }
    }
}

