}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ETG_ActualAgreement, CreateActual), FormControlEventType::Clicked)]
public static void CreateActual_OnClicked(FormControl sender, FormControlEventArgs e)
{
    FormDataSource          ETG_Actualagreement_DS = sender.formRun().dataSource(formDataSourceStr(ETG_Actualagreement, ETG_ActualagreementNew));
    MultiSelectionHelper    selectionHelper = MultiSelectionHelper::construct();
    ETG_ActualagreementNew  eTG_Actualagreement;
    ETGCreateJournalHelper  eTGCreateJournalHelper = new ETGCreateJournalHelper();

    selectionHelper.parmDataSource(ETG_Actualagreement_DS);
    eTG_Actualagreement  = selectionHelper.getFirst();

    if (eTG_Actualagreement.RecId)
    {
        while (eTG_Actualagreement.RecId != 0)
        {
            eTGCreateJournalHelper.CreateActualReverseJnl(eTG_Actualagreement.ETGLineestimationno,eTG_Actualagreement.RecId);
            eTGCreateJournalHelper.CreateActualJnl(eTG_Actualagreement.ETGLineestimationno,eTG_Actualagreement.RecId);
            eTG_Actualagreement = selectionHelper.getNext();
        }
    }

}
